sys_ui_page.client_script:
function onCancel() {
    GlideDialogWindow.get().destroy();
    return false;
}
function highlightErrorRow(rowIndex) {
    // First, remove error class from ALL rows
    var allRows = document.querySelectorAll('.table-modern tbody tr');
    allRows.forEach(function(row) {
        row.classList.remove('error-row');
    });

    // Then add error class to the specific row
    var row = document.querySelector('.table-modern tbody tr:nth-child(' + rowIndex + ')');

    if (row) {
        // Add error class
        row.classList.add('error-row');

        // Scroll the row into view
        row.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
}
function formatDateDDMMYYYY(dateStr) {
    var parts = dateStr.split("-"); // [yyyy, mm, dd]
    return parts[2] + "-" + parts[1] + "-" + parts[0];
}

function onSubmit() {
    var rowCount = parseInt(gel("row_count").value, 10);


    // decimal/float ONLY: allows "12.3", "0.5", ".5" but NOT "12"
    var decimalOnlyRegex = /^[0-9]*\.?[0-9]+$/;

    var scopeStart = document.getElementById("sysparm_start_date").value;
    var scopeStartDate = getDateFromFormat(scopeStart, g_user_date_format);

    var scopeEnd = document.getElementById("sysparm_end_date").value;
    var scopeEndDate = getDateFromFormat(scopeEnd, g_user_date_format);

    for (var i = 1; i <= rowCount; i++) {
        var activityName = (document.getElementById("activity_name_" + i)?.value || "this activity");

        var scopeVal = (document.getElementById("scope_" + i).value || "").trim();
        var startVal = (document.getElementById("start_" + i).value || "").trim();
        var endVal = (document.getElementById("end_" + i).value || "").trim();
        var applicableVal = (document.getElementById("u_applicable_" + i).value || "").trim();

        var formattedStartVal = formatDateDDMMYYYY(startVal);
        var startDate = getDateFromFormat(formattedStartVal, g_user_date_format);

        var formattedEndVal = formatDateDDMMYYYY(endVal);
        var endDate = getDateFromFormat(formattedEndVal, g_user_date_format);

        var requiredFields = (document.getElementById("required_" + i).value || "").split(",");

		// Skip validation if applicable is 'no'
		if (applicableVal.toLowerCase() == 'no') {
			continue; // Skip this loop
		}
        for (var j = 0; j < requiredFields.length; j++) {
            var field = requiredFields[j].trim().toLowerCase();

            if (field === "scope") {
                if (!scopeVal) {
					highlightErrorRow(i);
                    alert("Scope is mandatory for activity: " + activityName);
                    return false;
                }
                if (!decimalOnlyRegex.test(scopeVal)) {
					highlightErrorRow(i);
                    alert("Scope must be an integer or decimal for activity: " + activityName);
                    return false;
                }
            }

            if (field === "start") {
                if (!startVal) {
					highlightErrorRow(i);
                    alert("Planned Start Date is mandatory for activity: " + activityName);
                    return false;
                }
                if (startDate < scopeStartDate || startDate > scopeEndDate) {
					highlightErrorRow(i);
                    alert("Planned Start Date for activity " + activityName +
                          " must be within the Scope Start/End Dates.");
                    return false;
                }
                if (startDate > endDate) {
					highlightErrorRow(i);
                    alert("Start Date for activity " + activityName +
                          " cannot be after the End Date.");
                    return false;
                }
            }

            if (field === "end") {
                if (!endVal) {
					highlightErrorRow(i);
                    alert("Planned End Date is mandatory for activity: " + activityName);
                    return false;
                }
                if (endDate > scopeEndDate || endDate < scopeStartDate) {
					highlightErrorRow(i);
                    alert("Planned End Date for activity " + activityName +
                          " must be within the Scope Start/End Dates.");
                    return false;
                }
                if (endDate < startDate) {
					highlightErrorRow(i);
                    alert("End Date for activity " + activityName +
                          " cannot be before the Start Date.");
                    return false;
                }
            }
        }
    }
    document.getElementById("sysparm_action").value = "onSubmitScript";
    return true;
}

function onSave() {
    var rowCount = parseInt(document.getElementById("row_count").value, 10) || 0;

    var scopeStart = document.getElementById("sysparm_start_date").value;
    var scopeStartDate = getDateFromFormat(scopeStart, g_user_date_format);

    var scopeEnd = document.getElementById("sysparm_end_date").value;
    var scopeEndDate = getDateFromFormat(scopeEnd, g_user_date_format);

    var numberRegex = /^[0-9]+(\.[0-9]+)?$/;

    for (var i = 1; i <= rowCount; i++) {
        var activityName = (document.getElementById("activity_name_" + i)?.value || "this activity");

        var scopeVal = (document.getElementById("scope_" + i).value || "").trim();
        var startVal = (document.getElementById("start_" + i).value || "").trim();
        var endVal = (document.getElementById("end_" + i).value || "").trim();

        // Scope validation
        if (scopeVal && !numberRegex.test(scopeVal)) {
			highlightErrorRow(i);
            alert("Scope for activity " + activityName + " must be a valid number.");
            return false;
        }

        if (startVal && endVal) {
            var formattedStartVal = formatDateDDMMYYYY(startVal);
            var startDate = getDateFromFormat(formattedStartVal, g_user_date_format);

            var formattedEndVal = formatDateDDMMYYYY(endVal);
            var endDate = getDateFromFormat(formattedEndVal, g_user_date_format);

            if (startDate < scopeStartDate || startDate > scopeEndDate) {
				highlightErrorRow(i);
                alert("Planned Start Date for activity " + activityName +
                      " must be within the Scope Start/End Dates.");
                return false;
            }
            if (startDate > endDate) {
				highlightErrorRow(i);
                alert("Start Date for activity " + activityName +
                      " cannot be after the End Date.");
                return false;
            }

            if (endDate > scopeEndDate || endDate < scopeStartDate) {
				highlightErrorRow(i);
                alert("Planned End Date for activity " + activityName +
                      " must be within the Scope Start/End Dates.");
                return false;
            }
            if (endDate < startDate) {
				highlightErrorRow(i);
                alert("End Date for activity " + activityName +
                      " cannot be before the Start Date.");
                return false;
            }
        }
    }
    return true;
}

sys_ui_page.processing_script:
var rowCount = parseInt(request.getParameter("row_count"), 10) || 0;

var parentScopeId = "";
for (var i = 1; i <= rowCount; i++) {
	var sysId = request.getParameter("sys_id_" + i);
	var scopeVal = request.getParameter("scope_" + i);
	var startVal = request.getParameter("start_" + i);
	var endVal = request.getParameter("end_" + i);
	// For u_applicable
	var applicableVal = request.getParameter("u_applicable_" + i);

	// For primavera_activity_no
	var primaveraActivityNo = request.getParameter("primavera_activity_no_" + i);


	if (!sysId) {

		continue;
	}

	var gr = new GlideRecord("x_adga_project_p_0_activities");
	if (gr.get(sysId)) {

		if (gr.scope_ref) {
			parentScopeId = gr.scope_ref.toString();
		}
		gr.scope = scopeVal || "";
		gr.planned_start_date = startVal || "";
		gr.planned_end_date = endVal || "";
		// For u_applicable
		gr.u_applicable = applicableVal;
		// For primavera_activity_no
		gr.primavera_activity_no = primaveraActivityNo;

		gr.update();

	} else {

	}
}
var action = request.getParameter("sysparm_action");

if (action == 'onSubmitScript' && parentScopeId) {
	var scopeGR = new GlideRecord("x_adga_project_p_0_scope");
	if (scopeGR.get(parentScopeId)) {
		scopeGR.sub_state = "2";
		scopeGR.update();

		if (scopeGR.project) {
			var projectGR = new GlideRecord("x_adga_project_p_0_project");
			if (projectGR.get(scopeGR.project)) {
				projectGR.u_project_state = "In Progress";
				projectGR.update();

			}
		}

		// Create Monthly Activites in x_adga_project_p_0_monthly_activities  when user clicks on submit button in UI Page
		// For Each activity based on planned start date and end date create month wise records.
		var activitiesGR = new GlideRecord("x_adga_project_p_0_activities");
		activitiesGR.addQuery("scope_ref", parentScopeId);
		activitiesGR.addQuery("u_applicable", "yes"); // dont create monthly activites if it is no
		activitiesGR.query();

		while (activitiesGR.next()) {
			var startDate = activitiesGR.planned_start_date;
			var endDate = activitiesGR.planned_end_date;

			if (!startDate || !endDate) {

				continue;
			}

			var start = new GlideDateTime(startDate);
			var end = new GlideDateTime(endDate);

			// Get start month and year
			var currentDate = new GlideDateTime(start);

			// Loop through each month between start and end date
			while (currentDate.compareTo(end) <= 0) {
				var monthNum = parseInt(currentDate.getMonthLocalTime(), 10); // Returns 1-12 (January=1)
				var yearNum = parseInt(currentDate.getYearLocalTime(), 10);

				// Create new monthly activity record
				var monthlyGR = new GlideRecord("x_adga_project_p_0_monthly_activities");
				monthlyGR.initialize();
				monthlyGR.parent = activitiesGR.sys_id;
				monthlyGR.u_month = monthNum;
				monthlyGR.u_year = yearNum;
				monthlyGR.insert();

				// Move to next month
				currentDate.addMonthsLocalTime(1);
				currentDate.setDayOfMonthLocalTime(1); // Reset to first day of next month
			}
		}

	}
}



if (parentScopeId) {
	response.sendRedirect("x_adga_project_p_0_scope.do?sys_id=" + parentScopeId);
}
